'use client';

import { useRouter } from 'next/navigation';
import { useState } from 'react';

type Props = { className?: string };

export default function SyncGmailInboxButton({ className = '' }: Props) {
  const router = useRouter();
  const [busy, setBusy] = useState(false);
  const [note, setNote] = useState<string | null>(null);

  async function sync() {
    setNote(null);
    setBusy(true);
    try {
      const res = await fetch('/api/crm/sync-inbox', { method: 'POST' });
      const data = await res.json();
      if (!res.ok) {
        setNote(data.error || 'Sync failed');
        return;
      }
      const imp = typeof data.imported === 'number' ? data.imported : 0;
      const sk = typeof data.skipped === 'number' ? data.skipped : 0;
      setNote(`Imported ${imp} · skipped ${sk}`);
      router.refresh();
    } catch {
      setNote('Sync failed');
    } finally {
      setBusy(false);
    }
  }

  return (
    <div className={`flex flex-col gap-1 ${className}`}>
      <button
        type="button"
        onClick={sync}
        disabled={busy}
        className="inline-flex justify-center items-center px-3 py-2 rounded-lg border border-gray-200 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:opacity-50"
      >
        {busy ? 'Syncing inbox…' : 'Sync Gmail replies'}
      </button>
      {note && <p className="text-xs text-gray-500 max-w-xs">{note}</p>}
    </div>
  );
}
