export const LEAD_STATUSES = [
  'new_lead',
  'warm_lead',
  'active_customer',
  'delinquent',
  'inactive',
] as const;

export type LeadStatus = (typeof LEAD_STATUSES)[number];

export const LEAD_STATUS_LABELS: Record<LeadStatus, string> = {
  new_lead: 'New lead',
  warm_lead: 'Warm lead',
  active_customer: 'Active customer',
  delinquent: 'Delinquent',
  inactive: 'Inactive',
};

export interface CrmEmailMessage {
  id: string;
  direction: 'inbound' | 'outbound';
  from: string;
  to: string;
  subject: string;
  bodyText: string;
  bodyHtml?: string;
  messageId?: string;
  inReplyTo?: string;
  createdAt: string;
}

export interface LeadRecord {
  id: string;
  name: string;
  email: string;
  phone: string;
  physicalAddress: string;
  status: LeadStatus;
  notes: string;
  emails: CrmEmailMessage[];
  createdAt: string;
  updatedAt: string;
}

export interface CrmDatabase {
  version: 1;
  leads: LeadRecord[];
}
