'use client';

import Link from 'next/link';
import SyncGmailInboxButton from '@/components/crm/SyncGmailInboxButton';
import { useRouter } from 'next/navigation';
import { useEffect, useMemo, useState } from 'react';
import type { CrmEmailMessage, LeadRecord, LeadStatus } from '@/lib/crm-types';
import { LEAD_STATUSES, LEAD_STATUS_LABELS } from '@/lib/crm-types';

const inputClass =
  'w-full px-3 py-2 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-primary/25 focus:border-primary';

export default function LeadWorkspace({ initialLead }: { initialLead: LeadRecord }) {
  const router = useRouter();
  const [lead, setLead] = useState(initialLead);
  const [name, setName] = useState(lead.name);
  const [email, setEmail] = useState(lead.email);
  const [phone, setPhone] = useState(lead.phone);
  const [physicalAddress, setPhysicalAddress] = useState(lead.physicalAddress);
  const [status, setStatus] = useState<LeadStatus>(lead.status);
  const [notes, setNotes] = useState(lead.notes);

  const [saveState, setSaveState] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
  const [saveError, setSaveError] = useState('');

  const [mailSubject, setMailSubject] = useState('');
  const [mailBody, setMailBody] = useState('');
  const [mailBusy, setMailBusy] = useState(false);
  const [mailError, setMailError] = useState('');

  const [invoiceOpen, setInvoiceOpen] = useState(false);
  const [stripeLink, setStripeLink] = useState('');
  const [invoicePreview, setInvoicePreview] = useState<{
    subject: string;
    html: string;
    text: string;
  } | null>(null);
  const [invoiceBusy, setInvoiceBusy] = useState(false);
  const [invoiceError, setInvoiceError] = useState('');
  const [invoiceStep, setInvoiceStep] = useState<'link' | 'preview'>('link');

  const thread = useMemo(() => {
    return [...lead.emails].sort((a, b) => (a.createdAt > b.createdAt ? 1 : -1));
  }, [lead.emails]);

  useEffect(() => {
    setLead(initialLead);
    setName(initialLead.name);
    setEmail(initialLead.email);
    setPhone(initialLead.phone);
    setPhysicalAddress(initialLead.physicalAddress);
    setStatus(initialLead.status);
    setNotes(initialLead.notes);
  }, [initialLead]);

  async function saveProfile() {
    setSaveState('saving');
    setSaveError('');
    try {
      const res = await fetch(`/api/crm/leads/${lead.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          name,
          email,
          phone,
          physicalAddress,
          status,
          notes,
        }),
      });
      const data = await res.json();
      if (!res.ok) {
        setSaveState('error');
        setSaveError(data.error || 'Save failed');
        return;
      }
      setLead(data.lead);
      setSaveState('saved');
      setTimeout(() => setSaveState('idle'), 2000);
      router.refresh();
    } catch {
      setSaveState('error');
      setSaveError('Request failed');
    }
  }

  async function sendMail() {
    setMailError('');
    setMailBusy(true);
    try {
      const res = await fetch(`/api/crm/leads/${lead.id}/send-email`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ subject: mailSubject, text: mailBody }),
      });
      const data = await res.json();
      if (!res.ok) {
        setMailError(data.error || 'Send failed');
        return;
      }
      setMailSubject('');
      setMailBody('');
      const refresh = await fetch(`/api/crm/leads/${lead.id}`);
      const j = await refresh.json();
      if (j.lead) setLead(j.lead);
      router.refresh();
    } catch {
      setMailError('Request failed');
    } finally {
      setMailBusy(false);
    }
  }

  function openInvoice() {
    setInvoiceOpen(true);
    setStripeLink('');
    setInvoicePreview(null);
    setInvoiceError('');
    setInvoiceStep('link');
  }

  async function previewInvoice() {
    setInvoiceError('');
    setInvoiceBusy(true);
    try {
      const res = await fetch(`/api/crm/leads/${lead.id}/macros/send-invoice`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ stripePaymentLink: stripeLink, previewOnly: true }),
      });
      const data = await res.json();
      if (!res.ok) {
        setInvoiceError(data.error || 'Preview failed');
        return;
      }
      setInvoicePreview({ subject: data.subject, html: data.html, text: data.text });
      setInvoiceStep('preview');
    } catch {
      setInvoiceError('Request failed');
    } finally {
      setInvoiceBusy(false);
    }
  }

  async function sendInvoice() {
    setInvoiceError('');
    setInvoiceBusy(true);
    try {
      const res = await fetch(`/api/crm/leads/${lead.id}/macros/send-invoice`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ stripePaymentLink: stripeLink, previewOnly: false }),
      });
      const data = await res.json();
      if (!res.ok) {
        setInvoiceError(data.error || 'Send failed');
        return;
      }
      setInvoiceOpen(false);
      const refresh = await fetch(`/api/crm/leads/${lead.id}`);
      const j = await refresh.json();
      if (j.lead) setLead(j.lead);
      router.refresh();
    } catch {
      setInvoiceError('Request failed');
    } finally {
      setInvoiceBusy(false);
    }
  }

  async function deleteLead() {
    if (!confirm('Delete this lead and all stored messages? This cannot be undone.')) return;
    const res = await fetch(`/api/crm/leads/${lead.id}`, { method: 'DELETE' });
    if (res.ok) {
      router.push('/crm');
      router.refresh();
    }
  }

  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-start justify-between gap-4">
        <div>
          <Link href="/crm" className="text-sm text-gray-500 hover:text-primary mb-2 inline-block">
            ← All leads
          </Link>
          <h1 className="text-2xl font-bold text-gray-900 tracking-tight">{lead.name}</h1>
          <p className="text-gray-500 text-sm mt-1">{lead.email}</p>
        </div>
        <div className="flex flex-wrap gap-2">
          <button
            type="button"
            onClick={openInvoice}
            className="px-4 py-2 rounded-lg bg-primary text-white text-sm font-semibold hover:bg-primary-dark shadow-sm"
          >
            Send invoice
          </button>
          <button
            type="button"
            onClick={deleteLead}
            className="px-4 py-2 rounded-lg border border-gray-200 text-sm text-red-700 hover:bg-red-50"
          >
            Delete lead
          </button>
        </div>
      </div>

      <div className="grid lg:grid-cols-5 gap-8">
        <section className="lg:col-span-2 space-y-5">
          <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-5 space-y-4">
            <h2 className="text-sm font-semibold text-gray-900 uppercase tracking-wide">
              Contact
            </h2>
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Name</label>
              <input className={inputClass} value={name} onChange={(e) => setName(e.target.value)} />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Email</label>
              <input
                type="email"
                className={inputClass}
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Phone</label>
              <input className={inputClass} value={phone} onChange={(e) => setPhone(e.target.value)} />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Physical address</label>
              <textarea
                className={`${inputClass} min-h-[4rem] resize-y`}
                value={physicalAddress}
                onChange={(e) => setPhysicalAddress(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Status</label>
              <select
                className={inputClass}
                value={status}
                onChange={(e) => setStatus(e.target.value as LeadStatus)}
              >
                {LEAD_STATUSES.map((s) => (
                  <option key={s} value={s}>
                    {LEAD_STATUS_LABELS[s]}
                  </option>
                ))}
              </select>
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-500 mb-1">Notes</label>
              <textarea
                className={`${inputClass} min-h-[5rem] resize-y`}
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
              />
            </div>
            <div className="flex items-center gap-3 pt-2">
              <button
                type="button"
                onClick={saveProfile}
                disabled={saveState === 'saving'}
                className="px-4 py-2 rounded-lg bg-gray-900 text-white text-sm font-medium hover:bg-gray-800 disabled:opacity-50"
              >
                {saveState === 'saving' ? 'Saving…' : 'Save changes'}
              </button>
              {saveState === 'saved' && (
                <span className="text-sm text-emerald-600">Saved</span>
              )}
            </div>
            {saveError && <p className="text-sm text-red-600">{saveError}</p>}
          </div>

          <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-5 space-y-3">
            <h2 className="text-sm font-semibold text-gray-900 uppercase tracking-wide">
              Compose email
            </h2>
            <p className="text-xs text-gray-500">
              Sends via Gmail (<code className="text-[11px]">EMAIL_USER</code>). Replies show in Gmail
              first—use <strong>Sync Gmail replies</strong> above to attach them to Activity.
            </p>
            <input
              className={inputClass}
              placeholder="Subject"
              value={mailSubject}
              onChange={(e) => setMailSubject(e.target.value)}
            />
            <textarea
              className={`${inputClass} min-h-[8rem] resize-y`}
              placeholder="Message"
              value={mailBody}
              onChange={(e) => setMailBody(e.target.value)}
            />
            {mailError && <p className="text-sm text-red-600">{mailError}</p>}
            <button
              type="button"
              disabled={mailBusy || !mailSubject.trim() || !mailBody.trim()}
              onClick={sendMail}
              className="w-full py-2.5 rounded-lg bg-primary text-white text-sm font-semibold hover:bg-primary-dark disabled:opacity-50"
            >
              {mailBusy ? 'Sending…' : 'Send to customer'}
            </button>
          </div>
        </section>

        <section className="lg:col-span-3">
          <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 mb-3">
            <h2 className="text-sm font-semibold text-gray-900 uppercase tracking-wide">Activity</h2>
            <SyncGmailInboxButton className="sm:items-end" />
          </div>
          <div className="space-y-3">
            {thread.length === 0 ? (
              <div className="bg-white rounded-xl border border-dashed border-gray-200 p-8 text-center text-gray-500 text-sm">
                No messages yet. Outbound sends and inbound webhook deliveries appear here.
              </div>
            ) : (
              thread.map((m) => <EmailCard key={m.id} message={m} />)
            )}
          </div>
        </section>
      </div>

      {invoiceOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
          <div
            className="bg-white rounded-2xl shadow-xl border border-gray-200 max-w-lg w-full max-h-[90vh] overflow-hidden flex flex-col"
            role="dialog"
            aria-labelledby="invoice-title"
          >
            <div className="px-5 py-4 border-b border-gray-100 flex justify-between items-center">
              <h2 id="invoice-title" className="font-semibold text-gray-900">
                Send invoice
              </h2>
              <button
                type="button"
                onClick={() => setInvoiceOpen(false)}
                className="text-gray-400 hover:text-gray-600 text-xl leading-none px-1"
                aria-label="Close"
              >
                ×
              </button>
            </div>
            <div className="p-5 overflow-y-auto flex-1 space-y-4">
              {invoiceStep === 'link' && (
                <>
                  <p className="text-sm text-gray-600">
                    Paste your Stripe Payment Link. We&apos;ll merge{' '}
                    <strong>name</strong> and <strong>address</strong> from this lead into the message.
                  </p>
                  <input
                    className={inputClass}
                    placeholder="https://buy.stripe.com/…"
                    value={stripeLink}
                    onChange={(e) => setStripeLink(e.target.value)}
                  />
                </>
              )}
              {invoiceStep === 'preview' && invoicePreview && (
                <>
                  <p className="text-xs font-medium text-gray-500">Subject</p>
                  <p className="text-sm text-gray-900">{invoicePreview.subject}</p>
                  <p className="text-xs font-medium text-gray-500 mt-3">Preview</p>
                  <div
                    className="rounded-lg border border-gray-100 bg-gray-50/80 p-4 text-sm overflow-auto max-h-48"
                    dangerouslySetInnerHTML={{ __html: invoicePreview.html }}
                  />
                </>
              )}
              {invoiceError && <p className="text-sm text-red-600">{invoiceError}</p>}
            </div>
            <div className="px-5 py-4 border-t border-gray-100 flex gap-2 justify-end">
              {invoiceStep === 'link' ? (
                <>
                  <button
                    type="button"
                    onClick={() => setInvoiceOpen(false)}
                    className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-50 rounded-lg"
                  >
                    Cancel
                  </button>
                  <button
                    type="button"
                    disabled={invoiceBusy || !stripeLink.trim()}
                    onClick={previewInvoice}
                    className="px-4 py-2 rounded-lg bg-gray-900 text-white text-sm font-medium hover:bg-gray-800 disabled:opacity-50"
                  >
                    {invoiceBusy ? '…' : 'Preview'}
                  </button>
                </>
              ) : (
                <>
                  <button
                    type="button"
                    onClick={() => {
                      setInvoiceStep('link');
                      setInvoicePreview(null);
                    }}
                    className="px-4 py-2 text-sm text-gray-600 hover:bg-gray-50 rounded-lg"
                  >
                    Back
                  </button>
                  <button
                    type="button"
                    disabled={invoiceBusy}
                    onClick={sendInvoice}
                    className="px-4 py-2 rounded-lg bg-primary text-white text-sm font-semibold hover:bg-primary-dark disabled:opacity-50"
                  >
                    {invoiceBusy ? 'Sending…' : 'Send email'}
                  </button>
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function EmailCard({ message }: { message: CrmEmailMessage }) {
  const outbound = message.direction === 'outbound';
  return (
    <article
      className={`rounded-xl border p-4 text-sm ${
        outbound
          ? 'bg-primary/5 border-primary/15 ml-4 sm:ml-8'
          : 'bg-white border-gray-200 mr-4 sm:mr-8'
      }`}
    >
      <div className="flex flex-wrap items-baseline justify-between gap-2 mb-2">
        <span className={`font-semibold ${outbound ? 'text-primary-dark' : 'text-gray-900'}`}>
          {outbound ? 'You → customer' : 'Customer → you'}
        </span>
        <time className="text-xs text-gray-400">
          {new Date(message.createdAt).toLocaleString()}
        </time>
      </div>
      <p className="font-medium text-gray-800 mb-1">{message.subject || '(no subject)'}</p>
      <p className="text-gray-500 text-xs mb-2">
        {message.from} → {message.to}
      </p>
      <pre className="whitespace-pre-wrap font-sans text-gray-700 text-sm leading-relaxed">
        {message.bodyText}
      </pre>
    </article>
  );
}
